INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-535efab1-moex-00236', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '伊朗於2024年7月選出新總統，由改革派的心臟外科醫生佩澤什基安（MassoudPezeshkian）當選。關 於伊朗的政治制度與發展，下列敘述何者正確？', '["伊朗的現代化發展過程中，有三個截然不同但息息相關的時期：巴勒維王朝早期（1921-1941年）與 晚期（1941-1979年）以及伊斯蘭共和國（1979年迄今）", "二次大戰之後，英國主導伊朗進行的大規模政治改革，包括廢除君主制、修改其憲法及改變社會行 為者之間的權力關係", "巴勒維政府於1963年發動紅色革命，旨在對抗外國勢力對伊朗國內政治與經濟社會的干涉", "1979年宗教領袖何梅尼帶領的革命不僅廢除伊朗的君主制，更建立一個奉行世俗主義的現代國家"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00237', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '2024年6月的南非大選結果標示著非洲民族議會（ANC）獨大的時代告終，對該國民主政治的運作帶 來一定的影響。關於南非的民主政治制度，下列敘述何者錯誤？', '["南非的憲法具最高權威，且規定總統享有任命權與決策權", "為處理種族隔離制度的遺緒，南非於1995年成立「事實與調解委員會」落實轉型正義", "南非的國會屬於兩院制，包括國民大會（NationalAssembly）與省級國家議會（NationalCouncilof Provinces）", "南非總統由人民直選產生並組成政府，面臨不信任投票時必須解散國會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00238', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '民意調查是了解並且預測選舉結果的重要手段，不過，「全國性」的民意調查在美國總統大選當中， 可能不見得反映最後的選舉結果，其最主要的原因來自：', '["民意調查工具不準確，測不到真實民意", "美國民眾的拒訪率太高，往往抽不到足夠的樣本來推估民意", "間接選舉的制度設計，候選人在各州贏者全拿「選舉人團票」，選舉結果往往會由關鍵的幾個搖擺 州決定", "美國政治人物往往拒絕承認民調結果，把「抵制民調」當成一種動員的工具，所以民調測不準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00239', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '下列關於法國總統選舉制度及其效應的敘述何者錯誤？', '["該制為需要絕對多數的單一選舉，政黨支持具高度重要性", "若無人在第一輪投票中獲絕對多數有效票則舉行第二輪投票", "第一輪投票之所有候選人參與第二輪投票，獲絕對多數票者當選", "第二輪的投票往往鼓勵意識型態相近的政黨組成選舉聯盟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00240', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '關於法國總統大選與國會議員的選舉，下列何者錯誤？', '["國會議員與總統大選皆採用兩輪決選制。若第一輪沒有人贏得絕對多數，則取前兩名進入第二輪決選", "在兩輪決選制的情形下，讓各黨缺乏在一開始就合作的動機，所以會使得小黨林立", "在第二輪進行的時候，往往會有很多聯盟的出現，此時選民傾向於避免讓最不喜歡的那位候選人當 選，因此會有很多策略投票（棄保）的情形", "兩輪決選制容易出現多黨聯盟，這個現象最有名的解釋理論來自杜瓦傑法則（Duverger''slaw）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00241', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '英國在2024年進行大選，關於英國的憲政體制，下列何者錯誤？', '["國會選舉的時間是由首相決定的，但每一屆的任期最長不能超過5年", "國會選舉制度是全部採取單一選區相對多數決制，此制度的特色是刻意扭曲選票和席次的比例性， 讓選票集中在大黨以盡量避免聯合內閣的出現", "在大部分的時候，首相會選在民調最有利的時候解散國會，進行全面改選", "國會分成上議院和下議院，上議院由貴族組成，權力和下議院一樣大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00242', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '民粹主義是一種特別的政治現象。下列何者不屬於民粹主義式政治人物的特徵？', '["常常把人們分成菁英和一般人兩大類", "反對多元主義，認為社會上的意見都可以收攏，不存在太多不同的意見", "宣稱自己代表一般人，要打倒政治或者經濟上的優勢族群，認定這些優勢族群都對自己的群體不利", "民粹式的政客通常都具有極右翼的意識型態，通常會非常排外"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00243', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '在議會內閣制的國家當中，通常反對黨會指派國會議員擔任特定議題領域的監督者，這些人也會是將 來取得執政權後的內閣成員，這個團隊稱為：', '["專業議員", "監督委員會", "影子內閣", "後排議員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00244', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '關於「民主鞏固」，下列何者錯誤？', '["基本定義是指一個國家民主化之後，幾乎不再有倒退回威權政治的可能性", "杭廷頓認為，當一個國家的政權完成至少兩次政黨輪替後，就可以稱得上民主鞏固", "當人們都能夠接受民主的遊戲規則，沒有人挑戰民主的正當性，就可以稱得上民主鞏固", "只要達成民主鞏固的要件，就不會再有民主倒退的可能性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00245', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-113-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '拉丁美洲國家有很多和美國一樣採用總統制，但為什麼總統制在拉美的運行沒有像美國一樣順利？下 列何者是可能的原因？', '["拉美國家的人們在文化上比較傾向監督制衡，不喜歡讓總統掌握太多權力", "拉美國家的政黨體系偏向多黨制，讓總統制的運行較困難", "拉美國家受美國影響太深，常被美國惡意干預內政，所以總統制運作不好", "拉美國家的國會太過強勢，讓行政權常常無法做事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:34+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL)
